sys_script_include.script:
/**
 * @class RecordInserter
 * @description Provides a functionality to insert records during the installation.
 * @since 24/02/2026
 * @date  24/02/2026
 * @version 1.0.0
 * @author Thomas Grensemann E-Mail: <thomas.grensemann@t-systems.com>
 *
 */
class RecordInserter extends Record {

    /**
     * @description Inserts a new record.
	 * 
     * @param {String} source source application
	 * @param {String} reason reason of the operation
     * @param {String} table The table to be used.
     * @param {String} properties field values
     * @param {Boolean} stealth modify data with setWorkflow() and autoSysFields()
     *
     * @returns {String}  sys_id of the inserted record, or null if the record is not inserted.
     */
    recordInsert(source, reason, table, properties, stealth) {
        stealth = stealth || false;
        let result = '';

        if (UtilityFunctions.isValidTable(table)) {
            const params = {
                'table': table,
                'properties': JSON.stringify(properties),
                'stealth': UtilityFunctions.getBooleanValue(stealth),
                'result': ''
            };

            const script = ScriptBuider.getScriptRecordInsert();

            result = new ScriptEvaluator().executScript('global', script, params);

            this.processResult(result, source, 'Record insert', reason, table, properties);

        } else {
            this.LOG_HANDLER.error(source, 'Record insert failed', reason, table, properties);
        }

        return result;
    }

    _processResult(result, source, reason, table, properties) {
        if (result) {
            this.LOG_HANDLER.info(source, 'Record successfully inserted', reason, properties, {
                'targetRecord': result,
                'targetTable': table
            });
        } else {
            this.LOG_HANDLER.error(source, 'Record insert failed', reason, table, properties);
        }
    }

}
